//----------Build function to build the dialog of backprofile Main UI STARTS-----------------------------------//
void MRFCircumVentRefinementCmdDlg::Build()
{
	_pMainFrame = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgGridLayout | CATDlgFraNoTitle | CATDlgFraNoFrame);
	_pMainFrame->SetGridConstraints(0, 0, 5, 4, CATGRID_4SIDES);

	_pLabelCircumGeomSet = new CATDlgLabel(_pMainFrame, (const char*)"BackProfile Geometrical Set ", CATDlgLabLeft);
	_pSelectorListGeometricalSet = new CATDlgSelectorList(_pMainFrame, (const char*)"SelectorList_BackProfileGeomSet", CATDlgLabLeft );
	_pContextualMenuSelListGeomSet = new CATDlgContextualMenu(_pSelectorListGeometricalSet, (const char*)"Spinner Checking Dist");

	_pLabelCircumGeomSet->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);
	_pSelectorListGeometricalSet->SetGridConstraints(0, 1, 4, 1, CATGRID_4SIDES);
	_pSelectorListGeometricalSet->SetVisibleTextHeight(1);
	_pSelectorListGeometricalSet->SetLine("Select BackProfile Geometrical Set ...");

	_pLabelCheckingDistanceTolerance = new CATDlgLabel(_pMainFrame, (const char*)"Checking Distance ", CATDlgLabLeft);
	_pSpinnerTolerance = new CATDlgSpinner(_pMainFrame, (const char*)"Spinner Checking Dist",CATDlgSpnEntry);

	_pLabelCheckingDistanceTolerance->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);
	_pSpinnerTolerance->SetGridConstraints(1, 1, 1, 1, CATGRID_4SIDES);
	_pSpinnerTolerance->SetMinMaxStep(0, 5000, 1);
	_pSpinnerTolerance->SetFormat("%2gmm");

	_pPushButtonAnalyseRevol = new CATDlgPushButton(_pMainFrame, (const char*)"Analyse Revolve", CATDlgLabLeft);
	_pPushButtonAnalyseRevol->SetGridConstraints(1,2, 1, 1, CATGRID_4SIDES);

	_pMultiListFrame = new CATDlgFrame(_pMainFrame, (const char*)"MultiListFrame", 0 | CATDlgGridLayout | CATDlgFraNoTitle | CATDlgFraNoFrame);
	_pMultiListOnCircumVentCollections = new CATDlgMultiList(_pMultiListFrame, (const char*)"MultiList Collection");

	_pMultiListFrame->SetGridConstraints(2, 0, 5, 1, CATGRID_4SIDES);
	_pMultiListOnCircumVentCollections->SetGridConstraints(0, 0, 5, 1, CATGRID_4SIDES);
	

	CATUnicodeString strHeader[5];
	strHeader[0] = "First Revolute (1)";
	strHeader[1] = "Second Revolute (2)";
	strHeader[2] = "PointVents in 1";
	strHeader[3] = "PointVents in 2";
	strHeader[4] = "Merge / Lateral";

	_pMultiListOnCircumVentCollections->SetColumnTitles(5, strHeader);
	_pMultiListOnCircumVentCollections->SetColumnTextWidth(0, 15);
	_pMultiListOnCircumVentCollections->SetColumnTextWidth(1, 15);
	_pMultiListOnCircumVentCollections->SetColumnTextWidth(2, 7);
	_pMultiListOnCircumVentCollections->SetColumnTextWidth(3, 7);
	_pMultiListOnCircumVentCollections->SetColumnTextWidth(4, 10);
	_pMultiListOnCircumVentCollections->SetTitlesVisibility(CATDlgShow);
	_pMultiListOnCircumVentCollections->SetVisibleColumnCount(5);
	_pMultiListOnCircumVentCollections->SetVisibleLineCount(10);

	_pPushButtonMerge = new CATDlgPushButton(_pMainFrame, (const char*)"Merge Vent", CATDlgLabLeft );
	_pPushButtonLateral = new CATDlgPushButton(_pMainFrame, (const char*)"   Lateral Vent   ", CATDlgLabLeft);

	_pPushButtonMerge->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);
	_pPushButtonLateral->SetGridConstraints(3, 1, 1, 1, CATGRID_4SIDES);
	

	_pResetFrame = new CATDlgFrame(this, (const char*)"Reset", 0 | CATDlgGridLayout);
	_pResetFrame->SetGridConstraints(4, 0, 1, 1, CATGRID_4SIDES);


	_pLabelVentGeomSet = new CATDlgLabel(_pResetFrame, (const char*)"Vent_Geom_Set", CATDlgLabLeft);
	_pLabelVentGeomSet->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_pSelectorListVentGeomSet = new CATDlgSelectorList(_pResetFrame, (const char*)"SelectorList_VentsGeomSet", 0);
	_pSelectorListVentGeomSet->SetGridConstraints(0, 1, 1, 1, CATGRID_4SIDES);
	_pSelectorListVentGeomSet->SetVisibleTextHeight(1);
	_pSelectorListVentGeomSet->SetVisibleTextWidth(25);
	_pSelectorListVentGeomSet->SetLine("Select Vent Geom Set");

	_pLabelCircumGeomSet = new CATDlgLabel(_pResetFrame, (const char*)"CircumVent_Geom_Set", CATDlgLabLeft);
	_pLabelCircumGeomSet->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

	_pSelectorListCircumVentGeomSet = new CATDlgSelectorList(_pResetFrame, (const char*)"SelectorList_CircumVentsGeomSet", 0);
	_pSelectorListCircumVentGeomSet->SetGridConstraints(1, 1, 1, 1, CATGRID_4SIDES);
	_pSelectorListCircumVentGeomSet->SetVisibleTextHeight(1);
	_pSelectorListCircumVentGeomSet->SetVisibleTextWidth(25);
	_pSelectorListCircumVentGeomSet->SetLine("Select Circum Vent Geom Set");

	_pPushButtonReset = new CATDlgPushButton(_pResetFrame, (const char*)"   Reset   ");
	_pPushButtonReset->SetGridConstraints(2, 0, 2, 1, CATGRID_4SIDES);

	this->SetVisibility(CATDlgShow);

}


//-----------Function to set focus on selector List when selector list is clicked by user STARTS--------------//
void MRFCircumVentRefinementCmdDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}
//-----------Function to set focus on selector List when selector list is clicked by user STARTS--------------//


//------------Function to set name to be displayed at Surface Selector List STARTS------------//
void MRFCircumVentRefinementCmdDlg::SetSelectorListGeomSet(const CATUnicodeString ipSourceSurf, CATDlgSelectorList * spSelList)
{

	if (spSelList)
	{
		spSelList->ClearLine();
		spSelList->SetLine(ipSourceSurf);
		SetFocusOnSelectorList(spSelList);
	}
}
//------------Function to set name to be displayed at Surface Selector List ENDS------------//





